const { exec } = require('child_process');

module.exports = async function (context, req) {
    const inputFileName = req.body.inputFileName;
    const outputFormat = req.body.outputFormat;

    // Validate input to prevent command injection
    const validFormats = ['pdf', 'docx', 'odt', 'txt'];
    if (!inputFileName || !validFormats.includes(outputFormat)) {
        context.res = {
            status: 400,
            body: "Invalid input parameters."
        };
        return;
    }

    // Sanitize input file name
    const sanitizedInputFileName = inputFileName.replace(/[^a-zA-Z0-9_\-\.\/]/g, '');
    const sanitizedOutputFormat = outputFormat.replace(/[^a-zA-Z0-9]/g, '');

    const command = `libreoffice --headless --convert-to ${sanitizedOutputFormat} "${sanitizedInputFileName}"`;

    exec(command, (error, stdout, stderr) => {
        if (error) {
            context.res = {
                status: 500,
                body: `Error converting document: ${stderr}`
            };
            return;
        }
        context.res = {
            status: 200,
            body: `Document converted successfully: ${stdout}`
        };
    });
};